 1→package ingestion
 2→
 3→import (
 4→	"context"
 5→	"log/slog"
 6→
 7→	"github.com/google/uuid"
 8→	"github.com/sentioxyz/releaseguard/internal/models"
 9→)
10→
11→// Service orchestrates ingestion sources and persists normalized results.
12→type Service struct {
13→	store ReleaseStore
14→}
15→
16→func NewService(store ReleaseStore) *Service {
17→	return &Service{store: store}
18→}
19→
20→// ProcessResults normalizes raw ingestion results into ReleaseEvents and persists them.
21→// Duplicate releases (unique constraint violations) are logged and skipped, not fatal.
22→func (s *Service) ProcessResults(ctx context.Context, sourceID int, sourceName string, results []IngestionResult) error {
23→	for _, r := range results {
24→		event := &models.ReleaseEvent{
25→			ID:         uuid.New().String(),
26→			Source:     sourceName,
27→			Repository: r.Repository,
28→			RawVersion: r.RawVersion,
29→			Changelog:  r.Changelog,
30→			Metadata:   r.Metadata,
31→			Timestamp:  r.Timestamp,
32→		}
33→
34→		if err := s.store.IngestRelease(ctx, sourceID, event); err != nil {
35→			slog.Warn("ingest failed (may be duplicate)",
36→				"repo", r.Repository, "version", r.RawVersion, "err", err)
37→			continue
38→		}
39→	}
40→	return nil
41→}
