222→// --- ReleasesStore ---
223→
224→func (s *PgStore) ListReleases(ctx context.Context, opts ListReleasesOpts) ([]ReleaseView, int, error) {
225→	// Build dynamic WHERE clause.
226→	var conditions []string
227→	var args []any
228→	argIdx := 1
229→
230→	if opts.ProjectID != nil {
231→		conditions = append(conditions, fmt.Sprintf("p.id = $%d", argIdx))
232→		args = append(args, *opts.ProjectID)
233→		argIdx++
234→	}
235→	if opts.SourceID != nil {
236→		conditions = append(conditions, fmt.Sprintf("s.id = $%d", argIdx))
237→		args = append(args, *opts.SourceID)
238→		argIdx++
239→	}
240→
241→	where := ""
242→	if len(conditions) > 0 {
243→		where = " WHERE " + strings.Join(conditions, " AND ")
244→	}
245→
246→	// Count query.
247→	countQuery := `SELECT COUNT(*) FROM releases r
248→		JOIN sources s ON r.source_id = s.id
249→		JOIN projects p ON s.project_id = p.id` + where
250→	var total int
251→	err := s.pool.QueryRow(ctx, countQuery, args...).Scan(&total)
252→	if err != nil {
253→		return nil, 0, fmt.Errorf("count releases: %w", err)
254→	}
255→
256→	// Sort clause.
257→	sortCol := "r.created_at"
258→	if opts.Sort == "version" {
259→		sortCol = "r.version"
260→	}
261→	order := "DESC"
262→	if strings.EqualFold(opts.Order, "asc") {
263→		order = "ASC"
264→	}
265→
266→	// Data query.
267→	dataQuery := releaseViewQuery + where +
268→		fmt.Sprintf(" ORDER BY %s %s LIMIT $%d OFFSET $%d", sortCol, order, argIdx, argIdx+1)
269→	args = append(args, opts.PerPage, (opts.Page-1)*opts.PerPage)
270→
271→	rows, err := s.pool.Query(ctx, dataQuery, args...)
272→	if err != nil {
273→		return nil, 0, fmt.Errorf("list releases: %w", err)
274→	}
275→	defer rows.Close()
276→
277→	var releases []ReleaseView
278→	for rows.Next() {
279→		var rv ReleaseView
280→		var isPreStr string
281→		var createdAt time.Time
282→		if err := rows.Scan(&rv.ID, &rv.SourceID, &rv.SourceType, &rv.Repository, &rv.ProjectID, &rv.ProjectName,
283→			&rv.RawVersion, &isPreStr, &rv.PipelineStatus, &createdAt); err != nil {
284→			return nil, 0, fmt.Errorf("scan release: %w", err)
285→		}
286→		rv.IsPreRelease = isPreStr == "true"
287→		rv.CreatedAt = createdAt.Format(time.RFC3339)
288→		releases = append(releases, rv)
289→	}
290→	return releases, total, nil
291→}
