package ingestion

import (
	"context"
	"sync/atomic"
	"testing"
	"time"
)

type fakeSource struct {
	name     string
	sourceID int
	calls    atomic.Int32
	results  []IngestionResult
}

func (f *fakeSource) Name() string  { return f.name }
func (f *fakeSource) SourceID() int { return f.sourceID }

func (f *fakeSource) FetchNewReleases(_ context.Context) ([]IngestionResult, error) {
	f.calls.Add(1)
	return f.results, nil
}

func TestOrchestratorPollsOnInterval(t *testing.T) {
	store := &mockStore{}
	svc := NewService(store)

	src := &fakeSource{
		name:    "test",
		results: []IngestionResult{{Repository: "r", RawVersion: "v1", Timestamp: time.Now()}},
	}

	orch := NewOrchestrator(svc, []IIngestionSource{src}, 50*time.Millisecond)

	ctx, cancel := context.WithTimeout(context.Background(), 180*time.Millisecond)
	defer cancel()

	orch.Run(ctx)

	// With 50ms interval and 180ms timeout, expect: immediate poll + ~3 ticks = ~4 calls.
	// At minimum 2 calls proves the interval loop works.
	calls := int(src.calls.Load())
	if calls < 2 {
		t.Errorf("expected at least 2 poll calls, got %d", calls)
	}
}

func TestOrchestratorMultipleSources(t *testing.T) {
	store := &mockStore{}
	svc := NewService(store)

	src1 := &fakeSource{name: "a", results: []IngestionResult{{Repository: "r1", RawVersion: "v1", Timestamp: time.Now()}}}
	src2 := &fakeSource{name: "b", results: []IngestionResult{{Repository: "r2", RawVersion: "v2", Timestamp: time.Now()}}}

	orch := NewOrchestrator(svc, []IIngestionSource{src1, src2}, 50*time.Millisecond)

	ctx, cancel := context.WithTimeout(context.Background(), 80*time.Millisecond)
	defer cancel()

	orch.Run(ctx)

	if src1.calls.Load() < 1 {
		t.Error("source 1 was not polled")
	}
	if src2.calls.Load() < 1 {
		t.Error("source 2 was not polled")
	}
}

package main

import (
	"context"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"time"

	"github.com/riverqueue/river"
	"github.com/sentioxyz/releaseguard/internal/api"
	"github.com/sentioxyz/releaseguard/internal/db"
	"github.com/sentioxyz/releaseguard/internal/ingestion"
	"github.com/sentioxyz/releaseguard/internal/pipeline"
	"github.com/sentioxyz/releaseguard/internal/queue"
)

func main() {
	ctx, stop := signal.NotifyContext(context.Background(), os.Interrupt)
	defer stop()

	dbURL := envOr("DATABASE_URL", "postgres://localhost:5432/releaseguard?sslmode=disable")
	ghSecret := envOr("GITHUB_WEBHOOK_SECRET", "")
	addr := envOr("LISTEN_ADDR", ":8080")

	// Database
	pool, err := db.NewPool(ctx, dbURL)
	if err != nil {
		slog.Error("database connection failed", "err", err)
		os.Exit(1)
	}
	defer pool.Close()

	if err := db.RunMigrations(ctx, pool); err != nil {
		slog.Error("migrations failed", "err", err)
		os.Exit(1)
	}

	// Pipeline
	pipelineStore := pipeline.NewPgStore(pool)
	pipelineRunner := pipeline.NewRunner(
		pipelineStore,
		[]pipeline.PipelineNode{
			pipeline.NewRegexNormalizer(),
			pipeline.NewSubscriptionRouter(pipelineStore),
		},
		[]pipeline.PipelineNode{
			pipeline.NewUrgencyScorer(),
		},
	)

	// River queue with pipeline worker
	workers := river.NewWorkers()
	river.AddWorker(workers, pipeline.NewWorker(pipelineRunner))

	riverClient, err := queue.NewRiverClient(pool, workers)
	if err != nil {
		slog.Error("river client failed", "err", err)
		os.Exit(1)
	}

	if err := riverClient.Start(ctx); err != nil {
		slog.Error("river start failed", "err", err)
		os.Exit(1)
	}

	// Ingestion layer
	ingestionStore := ingestion.NewPgStore(pool, riverClient)
	svc := ingestion.NewService(ingestionStore)

	sources := []ingestion.IIngestionSource{
		ingestion.NewDockerHubSource(http.DefaultClient, "library/golang", 0),
	}

	orch := ingestion.NewOrchestrator(svc, sources, 5*time.Minute)

	// GitHub webhook handler
	webhookHandler := ingestion.NewGitHubWebhookHandler(ghSecret, func(results []ingestion.IngestionResult) {
		if err := svc.ProcessResults(ctx, 0, "github", results); err != nil {
			slog.Error("github webhook processing failed", "err", err)
		}
	})

	// API layer
	pgStore := api.NewPgStore(pool)
	broadcaster := api.NewBroadcaster()

	mux := http.NewServeMux()

	// Register webhook route
	mux.Handle("POST /webhook/github", webhookHandler)

	// Register all API v1 routes
	api.RegisterRoutes(mux, api.Dependencies{
		DB:                 pool,
		ProjectsStore:      pgStore,
		ReleasesStore:      pgStore,
		SubscriptionsStore: pgStore,
		SourcesStore:       pgStore,
		ChannelsStore:      pgStore,
		KeyStore:           pgStore,
		HealthChecker:      pgStore,
		Broadcaster:        broadcaster,
	})

	srv := &http.Server{Addr: addr, Handler: mux}

	// Start polling in background
	go orch.Run(ctx)

	// Start PostgreSQL LISTEN/NOTIFY → SSE bridge
	go api.ListenForNotifications(ctx, pool, broadcaster)

	// Start HTTP server
	go func() {
		slog.Info("server starting", "addr", srv.Addr)
		if err := srv.ListenAndServe(); err != http.ErrServerClosed {
			slog.Error("server error", "err", err)
		}
	}()

	<-ctx.Done()
	slog.Info("shutting down")

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	riverClient.Stop(shutdownCtx)
	srv.Shutdown(shutdownCtx)
}

func envOr(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

