 1→package ingestion
 2→
 3→import (
 4→	"context"
 5→	"log/slog"
 6→	"time"
 7→)
 8→
 9→// Orchestrator runs polling ingestion sources on a fixed interval.
10→type Orchestrator struct {
11→	service  *Service
12→	sources  []IIngestionSource
13→	interval time.Duration
14→}
15→
16→func NewOrchestrator(service *Service, sources []IIngestionSource, interval time.Duration) *Orchestrator {
17→	return &Orchestrator{service: service, sources: sources, interval: interval}
18→}
19→
20→// Run polls all sources immediately, then on every tick. Blocks until ctx is cancelled.
21→func (o *Orchestrator) Run(ctx context.Context) {
22→	ticker := time.NewTicker(o.interval)
23→	defer ticker.Stop()
24→
25→	o.pollAll(ctx)
26→
27→	for {
28→		select {
29→		case <-ctx.Done():
30→			return
31→		case <-ticker.C:
32→			o.pollAll(ctx)
33→		}
34→	}
35→}
36→
37→func (o *Orchestrator) pollAll(ctx context.Context) {
38→	for _, src := range o.sources {
39→		results, err := src.FetchNewReleases(ctx)
40→		if err != nil {
41→			slog.Error("poll failed", "source", src.Name(), "err", err)
42→			continue
43→		}
44→		if len(results) == 0 {
45→			continue
46→		}
47→		if err := o.service.ProcessResults(ctx, src.SourceID(), src.Name(), results); err != nil {
48→			slog.Error("process failed", "source", src.Name(), "err", err)
49→		}
50→	}
51→}
52→

