 29→func (s *PgStore) ListProjects(ctx context.Context, page, perPage int) ([]models.Project, int, error) {
 30→	var total int
 31→	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM projects`).Scan(&total)
 32→	if err != nil {
 33→		return nil, 0, fmt.Errorf("count projects: %w", err)
 34→	}
 35→	offset := (page - 1) * perPage
 36→	rows, err := s.pool.Query(ctx,
 37→		`SELECT id, name, COALESCE(description,''), COALESCE(url,''), pipeline_config, created_at, updated_at
 38→		 FROM projects ORDER BY created_at DESC LIMIT $1 OFFSET $2`, perPage, offset)
 39→	if err != nil {
 40→		return nil, 0, fmt.Errorf("list projects: %w", err)
 41→	}
 42→	defer rows.Close()
 43→	var projects []models.Project
 44→	for rows.Next() {
 45→		var p models.Project
 46→		if err := rows.Scan(&p.ID, &p.Name, &p.Description, &p.URL, &p.PipelineConfig, &p.CreatedAt, &p.UpdatedAt); err != nil {
 47→			return nil, 0, fmt.Errorf("scan project: %w", err)
 48→		}
 49→		projects = append(projects, p)
 50→	}
 51→	return projects, total, nil
 52→}
