 57→		 VALUES ($1, $2, $3, $4)
 58→		 RETURNING id, created_at, updated_at`,
 59→		p.Name, p.Description, p.URL, p.PipelineConfig,
 60→	).Scan(&p.ID, &p.CreatedAt, &p.UpdatedAt)
 61→}
